
import { useState, useEffect, useRef } from "react";

const LOGO_B64 = "data:image/jpeg;base64,";

// ─── MASTER DATA ───────────────────────────────────────────────────────────
const ASSESSMENT_TYPES = [
  { value: "ขายฝาก", icon: "🔏", color: "#f59e0b", desc: "รับซื้อฝาก / ไถ่ถอนภายหลัง" },
  { value: "จำนอง", icon: "🏦", color: "#3b82f6", desc: "จดจำนองที่สำนักงานที่ดิน" },
  { value: "ซื้อขาย", icon: "🤝", color: "#10b981", desc: "ประเมินเพื่อซื้อขายทั่วไป" },
  { value: "ประเมินเพื่อสินเชื่อ", icon: "📑", color: "#8b5cf6", desc: "ยื่นธนาคาร / สถาบันการเงิน" },
  { value: "ประเมินมูลค่าทรัพย์สิน", icon: "📊", color: "#c9a84c", desc: "รายงานมูลค่าทางบัญชี" },
  { value: "อื่นๆ", icon: "📋", color: "#64748b", desc: "" },
];

const PROPERTY_TYPES = [
  { group: "🏞️ ที่ดิน", items: [
    "ที่ดินเปล่า (โฉนด)",
    "ที่ดิน น.ส.3 / น.ส.3ก",
    "ที่ดินเกษตรกรรม",
    "สวนยาง / สวนปาล์ม / ไร่",
    "ที่ดินในนิคมอุตสาหกรรม",
  ]},
  { group: "🏠 ที่อยู่อาศัย", items: [
    "บ้านเดี่ยว",
    "บ้านแฝด",
    "ทาวน์เฮาส์ / ทาวน์โฮม",
    "บ้านชั้นเดียว",
    "วิลล่า / รีสอร์ทโฮม",
  ]},
  { group: "🏢 อาคารชุด / คอนโด", items: [
    "คอนโดมิเนียม",
    "อาคารชุดพักอาศัย",
    "เซอร์วิสอพาร์ทเมนท์",
  ]},
  { group: "🏪 พาณิชยกรรม", items: [
    "อาคารพาณิชย์ / ตึกแถว",
    "ศูนย์การค้า / คอมมูนิตี้มอลล์",
    "ออฟฟิศ / อาคารสำนักงาน",
    "โชว์รูม",
  ]},
  { group: "🏭 อุตสาหกรรม / โลจิสติกส์", items: [
    "โกดัง / คลังสินค้า",
    "โรงงานอุตสาหกรรม",
    "โกดังพร้อมออฟฟิศ",
  ]},
  { group: "🏨 โรงแรม / รีสอร์ท", items: [
    "โรงแรม",
    "รีสอร์ท",
    "บังกะโล / เกสต์เฮาส์",
  ]},
  { group: "🏗️ อื่นๆ", items: [
    "อพาร์ทเมนต์ / หอพัก",
    "สนามกีฬา / สถานบันเทิง",
    "โรงเรียน / โรงพยาบาล",
    "สุสาน / ฌาปนสถาน",
    "อสังหาฯ อื่นๆ",
  ]},
];

const ALL_PROPERTY_TYPES = PROPERTY_TYPES.flatMap(g => g.items);

const ZONE_MULTIPLIERS = {
  "ติดถนนใหญ่ 4 เลน+": 2.4,
  "ใกล้ถนนใหญ่ < 500 ม.": 1.8,
  "ซอยรอง ใกล้ชุมชน": 1.4,
  "ในซอย / เลียบคลอง": 1.1,
  "ซอยลึก / ห่างถนนใหญ่": 0.85,
};
const ROAD_WIDTH_BONUS = {
  "≥ 12 ม. (4 เลน)": 0.25,
  "8–11 ม. (2 เลน)": 0.12,
  "6–7 ม. (คสล.)": 0.0,
  "< 6 ม. / ทางเดิน": -0.15,
};
const FRONTAGE_BONUS = {
  "≥ 20 ม.": 0.18,
  "12–19 ม.": 0.1,
  "8–11 ม.": 0.03,
  "< 8 ม.": -0.08,
};
const ZONING_COLOR = {
  "ย.4 (สีเหลือง) — พักอาศัยหนาแน่นน้อย": { mult: 1.0, color: "#f5c842" },
  "ย.5–ย.7 (สีส้ม) — พักอาศัยหนาแน่นปานกลาง": { mult: 1.15, color: "#f5842d" },
  "พ.1–พ.5 (สีแดง) — พาณิชยกรรม": { mult: 1.35, color: "#e03e3e" },
  "ก.1–ก.3 (สีเขียว) — เกษตรกรรม": { mult: 0.7, color: "#4caf50" },
  "ท.1–ท.3 (สีม่วง) — อุตสาหกรรม": { mult: 1.2, color: "#9c27b0" },
  "ไม่ทราบ": { mult: 1.0, color: "#888" },
};
const FILL_STATUS = {
  "ถมแล้ว เรียบร้อย": 0.15,
  "ถมบางส่วน": 0.05,
  "ยังไม่ถม": 0.0,
  "ที่ลุ่ม / น้ำท่วมซ้ำซาก": -0.2,
};
const RISK_FACTORS = [
  { key: "flood", label: "เสี่ยงน้ำท่วม", weight: 15 },
  { key: "access", label: "เข้าถึงยาก / ซอยตัน", weight: 10 },
  { key: "shape", label: "รูปแปลงผิดปกติ", weight: 8 },
  { key: "encumbrance", label: "มีภาระผูกพัน", weight: 20 },
  { key: "dispute", label: "มีข้อพิพาท / ครอบครอง", weight: 25 },
  { key: "utility", label: "ไม่มีสาธารณูปโภค", weight: 7 },
  { key: "adjacent", label: "ติดสิ่งรบกวน (โรงงาน/กม.)", weight: 10 },
  { key: "title", label: "โฉนดไม่สมบูรณ์ / น.ส.3", weight: 15 },
];

const scoreColor = (s) => s >= 75 ? "#4ade80" : s >= 55 ? "#facc15" : s >= 35 ? "#fb923c" : "#f87171";
const scoreLabel = (s) => s >= 75 ? "ดีมาก ✅" : s >= 55 ? "ปานกลาง ⚠️" : s >= 35 ? "เสี่ยงสูง 🔶" : "เสี่ยงมาก ❌";
const fmt = (n) => Math.round(n).toLocaleString("th-TH");

// ─── APP ───────────────────────────────────────────────────────────────────
export default function App() {
  const [view, setView] = useState("form"); // "form" | "history" | "settings"
  const [step, setStep] = useState(1);
  const [records, setRecords] = useState([]);
  const [propGroup, setPropGroup] = useState(PROPERTY_TYPES[0].group);
  const [now, setNow] = useState(new Date());
  useEffect(() => { const t = setInterval(()=>setNow(new Date()), 1000); return ()=>clearInterval(t); }, []);
  const [gsheetUrl, setGsheetUrl] = useState("");
  const [saveStatus, setSaveStatus] = useState(null); // null | "saving" | "ok" | "error"
  const [selectedRecord, setSelectedRecord] = useState(null);
  const [settingInput, setSettingInput] = useState("");

  const initForm = () => ({
    assessmentType: "ขายฝาก",
    propertyType: "ที่ดินเปล่า (โฉนด)",
    projectName: "",
    date: new Date().toISOString().split("T")[0],
    analyst: "",
    titleDeed: "", surveyPage: "", parcelNo: "",
    subdistrict: "", district: "", province: "กรุงเทพมหานคร",
    rai: 0, ngaan: 0, sqwa: 0,
    govPrice: 0,
    zone: "ในซอย / เลียบคลอง",
    roadWidth: "6–7 ม. (คสล.)",
    frontage: "8–11 ม.",
    zoning: "ย.4 (สีเหลือง) — พักอาศัยหนาแน่นน้อย",
    fillStatus: "ยังไม่ถม",
    distanceMainRoad: "",
    noteLocation: "",
    risks: {},
    ltvRate: 50,
    compPrice: "",
    compNote: "",
  });

  const [form, setForm] = useState(initForm());
  const setF = (k, v) => setForm(p => ({ ...p, [k]: v }));
  const toggleRisk = (k) => setF("risks", { ...form.risks, [k]: !form.risks[k] });

  // Load persisted data
  useEffect(() => {
    const load = async () => {
      try {
        const r = await window.storage.get("propval_records");
        if (r) setRecords(JSON.parse(r.value));
        const s = await window.storage.get("propval_gsheet_url");
        if (s) { setGsheetUrl(s.value); setSettingInput(s.value); }
      } catch(_) {}
    };
    load();
  }, []);

  // ── Calculations ──
  const totalSqwa = parseFloat(form.rai)*400 + parseFloat(form.ngaan)*100 + parseFloat(form.sqwa);
  const govTotal = totalSqwa * parseFloat(form.govPrice||0);
  const zoneMult = ZONE_MULTIPLIERS[form.zone]||1.0;
  const roadBonus = ROAD_WIDTH_BONUS[form.roadWidth]||0;
  const frontBonus = FRONTAGE_BONUS[form.frontage]||0;
  const zoningMult = ZONING_COLOR[form.zoning]?.mult||1.0;
  const fillBonus = FILL_STATUS[form.fillStatus]||0;
  const marketPricePerSqwa = parseFloat(form.govPrice||0)*zoneMult*zoningMult*(1+roadBonus+frontBonus+fillBonus);
  const marketTotal = marketPricePerSqwa*totalSqwa;
  const compPriceNum = parseFloat(form.compPrice||0);
  const finalMarketPrice = compPriceNum>0 ? compPriceNum*totalSqwa : marketTotal;
  const finalPricePerSqwa = compPriceNum>0 ? compPriceNum : marketPricePerSqwa;
  const activeRisks = RISK_FACTORS.filter(r => form.risks[r.key]);
  const riskScore = activeRisks.reduce((s,r) => s+r.weight, 0);
  const maxRisk = RISK_FACTORS.reduce((s,r) => s+r.weight, 0);
  const propertyScore = Math.max(0, Math.round(100-(riskScore/maxRisk)*100));
  const fsvDiscount = riskScore>=40?0.65:riskScore>=20?0.75:0.80;
  const fsv = finalMarketPrice*fsvDiscount;
  const safetyLoan = fsv*(parseFloat(form.ltvRate)/100);

  // ── Save to Storage + Google Sheets ──
  const handleSave = async () => {
    setSaveStatus("saving");
    const record = {
      id: Date.now(),
      assessmentType: form.assessmentType,
      propertyType: form.propertyType,
      projectName: form.projectName,
      date: form.date,
      analyst: form.analyst,
      titleDeed: form.titleDeed,
      subdistrict: form.subdistrict,
      district: form.district,
      province: form.province,
      areaSqwa: totalSqwa,
      govPricePerSqwa: parseFloat(form.govPrice||0),
      govTotal,
      marketPricePerSqwa: finalPricePerSqwa,
      marketTotal: finalMarketPrice,
      fsv,
      ltvRate: form.ltvRate,
      loanAmount: safetyLoan,
      propertyScore,
      risks: activeRisks.map(r=>r.label).join(", "),
      zone: form.zone,
      zoning: form.zoning,
      fillStatus: form.fillStatus,
      noteLocation: form.noteLocation,
    };
    const newRecords = [record, ...records];
    setRecords(newRecords);
    try {
      await window.storage.set("propval_records", JSON.stringify(newRecords));
    } catch(_) {}

    // Google Sheets
    if (gsheetUrl) {
      try {
        const cols = [
          record.date, record.assessmentType, record.propertyType,
          record.projectName, record.titleDeed,
          record.subdistrict, record.district, record.province,
          record.areaSqwa, record.govPricePerSqwa, record.govTotal,
          record.marketPricePerSqwa, record.marketTotal,
          record.fsv, record.ltvRate, record.loanAmount,
          record.propertyScore, record.risks,
          record.zone, record.zoning, record.fillStatus,
          record.analyst, record.noteLocation,
        ];
        await fetch(gsheetUrl, {
          method: "POST",
          mode: "no-cors",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ action: "append", row: cols }),
        });
        setSaveStatus("ok");
      } catch(_) {
        setSaveStatus("error");
      }
    } else {
      setSaveStatus("ok");
    }
    setTimeout(() => setSaveStatus(null), 3500);
  };

  const handleDeleteRecord = async (id) => {
    const next = records.filter(r => r.id !== id);
    setRecords(next);
    try { await window.storage.set("propval_records", JSON.stringify(next)); } catch(_) {}
  };

  const saveSettings = async () => {
    setGsheetUrl(settingInput);
    try { await window.storage.set("propval_gsheet_url", settingInput); } catch(_) {}
  };

  const steps = ["ประเภท & โฉนด", "ปัจจัยทำเล", "ความเสี่ยง", "ผลประเมิน"];

  // ───────────────────────────────────────────────────────────────────────
  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sarabun:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500;600&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        body{background:#080c14;font-family:'Sarabun',sans-serif;color:#e2e8f0;}
        :root{
          --gold:#c9a84c;--gold2:#f0c97a;
          --bg0:#080c14;--bg1:#0d1422;--bg2:#111827;--bg3:#1a2235;
          --border:#1e2d45;--text1:#f0f4ff;--text2:#8fa3bf;
          --green:#4ade80;--red:#f87171;--orange:#fb923c;
        }
        input,select,textarea{font-family:'Sarabun',sans-serif;}
        ::-webkit-scrollbar{width:6px;}
        ::-webkit-scrollbar-track{background:#111827;}
        ::-webkit-scrollbar-thumb{background:#1e2d45;border-radius:3px;}
        .nav-tab{cursor:pointer;padding:10px 18px;border-radius:8px;font-size:14px;transition:all .2s;border:1px solid transparent;display:flex;align-items:center;gap:8px;}
        .nav-tab:hover{background:rgba(201,168,76,.08);}
        .nav-tab.active{background:rgba(201,168,76,.15);border-color:var(--gold);color:var(--gold2);}
        @media print{
          .no-print{display:none!important;}
          body{background:white;color:black;}
          .print-page{background:white!important;color:black!important;padding:20px;}
        }
      `}</style>

      <div style={{minHeight:"100vh",background:"var(--bg0)"}}>

        {/* ── HEADER ── */}
        <div style={{
          background:"#ffffff",borderBottom:"2px solid var(--gold)",
          boxShadow:"0 2px 20px rgba(0,0,0,.25)",position:"sticky",top:0,zIndex:100
        }}>
          {/* Top row: logo + clock */}
          <div style={{
            display:"flex",alignItems:"center",justifyContent:"space-between",
            padding:"10px 16px",flexWrap:"wrap",gap:8
          }}>
            {/* Logo + subtitle */}
            <div style={{display:"flex",alignItems:"center",gap:12,minWidth:0,flex:1}}>
              <img src={LOGO_B64} alt="AssetX" style={{height:40,objectFit:"contain",flexShrink:0}} />
              <div style={{borderLeft:"1px solid #e5e7eb",paddingLeft:12,minWidth:0}}>
                <div style={{fontSize:11,color:"#888",fontFamily:"'IBM Plex Mono',monospace",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                  ระบบประเมินมูลค่าอสังหาริมทรัพย์
                </div>
                <div style={{fontSize:10,color:"var(--gold)",fontFamily:"'IBM Plex Mono',monospace",letterSpacing:1}}>
                  PropVal Pro v2.0
                </div>
              </div>
            </div>

            {/* Clock widget */}
            <div style={{
              display:"flex",flexDirection:"column",alignItems:"center",
              background:"linear-gradient(135deg,#0d1422,#111827)",
              border:"1px solid var(--gold)",borderRadius:10,
              padding:"6px 14px",boxShadow:"0 0 12px rgba(201,168,76,.15)",
              flexShrink:0
            }}>
              <div style={{
                fontFamily:"'IBM Plex Mono',monospace",fontVariantNumeric:"tabular-nums",
                fontSize:"clamp(18px,4vw,26px)",fontWeight:700,
                color:"var(--gold2)",letterSpacing:"0.12em",lineHeight:1
              }}>
                {now.toLocaleTimeString("th-TH",{hour:"2-digit",minute:"2-digit",second:"2-digit",hour12:false})}
              </div>
              <div style={{
                fontFamily:"'Sarabun',sans-serif",fontSize:"clamp(10px,2.5vw,12px)",
                color:"#8fa3bf",marginTop:3,letterSpacing:.3,whiteSpace:"nowrap"
              }}>
                {now.toLocaleDateString("th-TH",{weekday:"long",day:"numeric",month:"long",year:"numeric"})}
              </div>
            </div>
          </div>

          {/* Bottom row: nav tabs */}
          <div className="no-print" style={{
            display:"flex",gap:4,padding:"0 12px 8px",
            overflowX:"auto",WebkitOverflowScrolling:"touch"
          }}>
            {[
              {id:"form",icon:"📋",label:"ประเมินทรัพย์"},
              {id:"history",icon:"📁",label:`ประวัติ (${records.length})`},
              {id:"settings",icon:"⚙️",label:"ตั้งค่า"},
            ].map(t => (
              <div key={t.id} className={`nav-tab${view===t.id?" active":""}`}
                onClick={()=>setView(t.id)}
                style={{whiteSpace:"nowrap",fontSize:"clamp(12px,3vw,14px)",padding:"7px 14px"}}>
                {t.icon} {t.label}
              </div>
            ))}
          </div>
        </div>

        {/* ═══════════════════════════════════ FORM VIEW ══════════════════════════ */}
        {view === "form" && (
          <div style={{paddingBottom:60}}>

            {/* Step indicator */}
            <div className="no-print" style={{
              display:"flex",justifyContent:"center",gap:0,padding:"20px 32px",
              borderBottom:"1px solid var(--border)"
            }}>
              {steps.map((s,i) => (
                <div key={i} style={{display:"flex",alignItems:"center"}}>
                  <div onClick={()=>setStep(i+1)} style={{
                    display:"flex",alignItems:"center",gap:8,padding:"8px 16px",
                    borderRadius:8,cursor:"pointer",transition:"all .2s",
                    background:step===i+1?"rgba(201,168,76,.15)":"transparent",
                    border:step===i+1?"1px solid var(--gold)":"1px solid transparent"
                  }}>
                    <div style={{
                      width:26,height:26,borderRadius:"50%",display:"flex",alignItems:"center",
                      justifyContent:"center",fontSize:12,fontWeight:700,flexShrink:0,
                      background:step>i?"var(--gold)":step===i+1?"var(--gold)":"var(--bg3)",
                      color:step>=i+1?"#080c14":"var(--text2)"
                    }}>{step>i+1?"✓":i+1}</div>
                    <span style={{fontSize:13,fontWeight:step===i+1?600:400,color:step===i+1?"var(--gold2)":"var(--text2)"}}>{s}</span>
                  </div>
                  {i<steps.length-1 && <div style={{width:28,height:1,background:"var(--border)"}} />}
                </div>
              ))}
            </div>

            <div style={{maxWidth:940,margin:"0 auto",padding:"28px 20px"}}>

              {/* ─── STEP 1 ─── */}
              {step===1 && (
                <div>
                  <STitle icon="📋" title="ประเภทการประเมินและข้อมูลโฉนด" sub="เลือกประเภทและกรอกข้อมูลทรัพย์" />

                  {/* Assessment Type */}
                  <Card title="🔖 ประเภทการประเมิน">
                    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:10}}>
                      {ASSESSMENT_TYPES.map(t => (
                        <div key={t.value} onClick={()=>setF("assessmentType",t.value)} style={{
                          padding:"14px 16px",borderRadius:10,cursor:"pointer",transition:"all .2s",
                          background:form.assessmentType===t.value?`${t.color}18`:"var(--bg3)",
                          border:`2px solid ${form.assessmentType===t.value?t.color:"var(--border)"}`,
                        }}>
                          <div style={{fontSize:22,marginBottom:6}}>{t.icon}</div>
                          <div style={{fontSize:14,fontWeight:600,color:form.assessmentType===t.value?t.color:"var(--text1)"}}>{t.value}</div>
                          {t.desc && <div style={{fontSize:11,color:"var(--text2)",marginTop:2}}>{t.desc}</div>}
                        </div>
                      ))}
                    </div>
                  </Card>

                  {/* Property Type */}
                  <div style={{marginTop:16}}>
                    <Card title="🏠 ประเภทอสังหาริมทรัพย์">
                      {/* Group selector */}
                      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8,marginBottom:14}}>
                        {PROPERTY_TYPES.map(g => {
                          const active = propGroup===g.group;
                          return (
                            <div key={g.group} onClick={()=>{
                              setPropGroup(g.group);
                              setF("propertyType", g.items[0]);
                            }} style={{
                              padding:"10px 12px",borderRadius:10,cursor:"pointer",transition:"all .2s",textAlign:"center",
                              background:active?"rgba(201,168,76,.18)":"var(--bg3)",
                              border:`2px solid ${active?"var(--gold)":"var(--border)"}`,
                            }}>
                              <div style={{fontSize:20,marginBottom:4}}>{g.group.split(" ")[0]}</div>
                              <div style={{fontSize:12,fontWeight:active?600:400,color:active?"var(--gold2)":"var(--text2)",lineHeight:1.3}}>
                                {g.group.replace(/^[\S]+\s/,"")}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                      {/* Sub-type dropdown */}
                      <div>
                        <div style={{fontSize:12,color:"var(--text2)",marginBottom:6}}>ประเภทย่อย</div>
                        <select value={form.propertyType} onChange={e=>setF("propertyType",e.target.value)}
                          style={{width:"100%",padding:"10px 14px",background:"var(--bg3)",border:"2px solid var(--gold)",
                            borderRadius:8,color:"var(--gold2)",fontSize:14,fontWeight:600,outline:"none"}}>
                          {(PROPERTY_TYPES.find(g=>g.group===propGroup)||PROPERTY_TYPES[0]).items.map(item => (
                            <option key={item} value={item}>{item}</option>
                          ))}
                        </select>
                        <div style={{marginTop:8,padding:"8px 14px",borderRadius:8,background:"rgba(201,168,76,.06)",border:"1px solid rgba(201,168,76,.2)",fontSize:13,color:"var(--text2)",display:"flex",alignItems:"center",gap:8}}>
                          <span style={{fontSize:16}}>{PROPERTY_TYPES.find(g=>g.group===propGroup)?.group.split(" ")[0]}</span>
                          <span><strong style={{color:"var(--gold2)"}}>{form.propertyType}</strong></span>
                        </div>
                      </div>
                    </Card>
                  </div>

                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginTop:16}}>
                    <Card title="ข้อมูลการประเมิน">
                      <Row label="ชื่อโครงการ / รหัสทรัพย์"><Input value={form.projectName} onChange={v=>setF("projectName",v)} placeholder="เช่น ที่ดินเลียบคลองฯ ซ.20" /></Row>
                      <Row label="วันที่ประเมิน"><Input type="date" value={form.date} onChange={v=>setF("date",v)} /></Row>
                      <Row label="ผู้ประเมิน"><Input value={form.analyst} onChange={v=>setF("analyst",v)} placeholder="ชื่อผู้ประเมิน" /></Row>
                    </Card>
                    <Card title="เลขที่โฉนด">
                      <Row label="เลขโฉนดที่ดิน"><Input value={form.titleDeed} onChange={v=>setF("titleDeed",v)} placeholder="เช่น 89062" /></Row>
                      <Row label="หน้าสำรวจ"><Input value={form.surveyPage} onChange={v=>setF("surveyPage",v)} placeholder="เช่น 12560" /></Row>
                      <Row label="เลขที่ดิน"><Input value={form.parcelNo} onChange={v=>setF("parcelNo",v)} placeholder="เช่น 10" /></Row>
                    </Card>
                    <Card title="ที่ตั้ง">
                      <Row label="ตำบล/แขวง"><Input value={form.subdistrict} onChange={v=>setF("subdistrict",v)} placeholder="เช่น หนองแขม" /></Row>
                      <Row label="อำเภอ/เขต"><Input value={form.district} onChange={v=>setF("district",v)} placeholder="เช่น ภาษีเจริญ" /></Row>
                      <Row label="จังหวัด"><Input value={form.province} onChange={v=>setF("province",v)} /></Row>
                    </Card>
                    <Card title="เนื้อที่และราคาประเมิน">
                      <Row label="เนื้อที่ (ไร่-งาน-ตรว.)">
                        <div style={{display:"flex",gap:8}}>
                          <NumIn value={form.rai} onChange={v=>setF("rai",v)} lbl="ไร่" />
                          <NumIn value={form.ngaan} onChange={v=>setF("ngaan",v)} lbl="งาน" />
                          <NumIn value={form.sqwa} onChange={v=>setF("sqwa",v)} lbl="ตรว." />
                        </div>
                      </Row>
                      <Row label="ราคาประเมิน กรมธนารักษ์">
                        <div style={{display:"flex",alignItems:"center",gap:8}}>
                          <Input type="number" value={form.govPrice} onChange={v=>setF("govPrice",v)} placeholder="0" />
                          <span style={{color:"var(--text2)",whiteSpace:"nowrap",fontSize:13}}>บาท/ตรว.</span>
                        </div>
                      </Row>
                      {totalSqwa>0 && form.govPrice>0 && (
                        <InfoBox value={`฿${fmt(govTotal)}`} label={`มูลค่าตามราคาประเมินรัฐ • ${fmt(totalSqwa)} ตรว.`} />
                      )}
                    </Card>
                  </div>
                  <NavBtn onNext={()=>setStep(2)} />
                </div>
              )}

              {/* ─── STEP 2 ─── */}
              {step===2 && (
                <div>
                  <STitle icon="🗺️" title="ปัจจัยทำเลและสภาพที่ดิน" sub="ข้อมูลเหล่านี้ส่งผลต่อราคาตลาดโดยตรง" />
                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
                    <Card title="ทำเลและการเข้าถึง">
                      <Row label="ทำเล / ระยะจากถนนใหญ่"><Sel value={form.zone} onChange={v=>setF("zone",v)} opts={Object.keys(ZONE_MULTIPLIERS)} /></Row>
                      <Row label="ความกว้างถนนหน้าที่ดิน"><Sel value={form.roadWidth} onChange={v=>setF("roadWidth",v)} opts={Object.keys(ROAD_WIDTH_BONUS)} /></Row>
                      <Row label="หน้ากว้างที่ดิน"><Sel value={form.frontage} onChange={v=>setF("frontage",v)} opts={Object.keys(FRONTAGE_BONUS)} /></Row>
                      <Row label="ระยะห่างถนนใหญ่"><Input value={form.distanceMainRoad} onChange={v=>setF("distanceMainRoad",v)} placeholder="เช่น 845 เมตร" /></Row>
                    </Card>
                    <Card title="ลักษณะที่ดินและผังเมือง">
                      <Row label="ผังเมือง (สี)"><Sel value={form.zoning} onChange={v=>setF("zoning",v)} opts={Object.keys(ZONING_COLOR)} /></Row>
                      <Row label="สภาพการถม"><Sel value={form.fillStatus} onChange={v=>setF("fillStatus",v)} opts={Object.keys(FILL_STATUS)} /></Row>
                      <Row label="ราคาตลาดอ้างอิง (Comp)">
                        <div style={{display:"flex",alignItems:"center",gap:8}}>
                          <Input type="number" value={form.compPrice} onChange={v=>setF("compPrice",v)} placeholder="ระบุถ้ามี" />
                          <span style={{color:"var(--text2)",whiteSpace:"nowrap",fontSize:13}}>บาท/ตรว.</span>
                        </div>
                      </Row>
                      <Row label="แหล่งที่มา Comp"><Input value={form.compNote} onChange={v=>setF("compNote",v)} placeholder="เช่น ซ.20 ถมแล้ว" /></Row>
                    </Card>
                  </div>
                  <div style={{marginTop:16}}>
                    <Card title="📊 ผลคำนวณราคาตลาดเบื้องต้น">
                      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12}}>
                        <StatBox label="ราคาประเมินรัฐ" value={`฿${fmt(parseFloat(form.govPrice||0))}`} sub="บาท/ตรว." color="#8fa3bf" />
                        <StatBox label="ราคาตลาดคำนวณ" value={`฿${fmt(marketPricePerSqwa)}`} sub="บาท/ตรว." color="var(--gold2)" />
                        <StatBox label={compPriceNum>0?"Comp อ้างอิง":"ราคาตลาด/ตรว."} value={`฿${fmt(finalPricePerSqwa)}`} sub="บาท/ตรว." color="#60a5fa" />
                        <StatBox label="มูลค่าตลาดรวม" value={`฿${fmt(finalMarketPrice)}`} sub="บาท" color="var(--green)" />
                      </div>
                    </Card>
                  </div>
                  <Row label="หมายเหตุทำเล / สภาพพื้นที่">
                    <textarea value={form.noteLocation} onChange={e=>setF("noteLocation",e.target.value)}
                      placeholder="บันทึกเพิ่มเติม เช่น สภาพพื้นที่ ทิศทาง สิ่งแวดล้อม..."
                      style={{width:"100%",minHeight:72,padding:"10px 14px",background:"var(--bg3)",
                        border:"1px solid var(--border)",borderRadius:8,color:"var(--text1)",fontSize:14,
                        fontFamily:"'Sarabun',sans-serif",resize:"vertical",marginTop:8}} />
                  </Row>
                  <NavBtn onBack={()=>setStep(1)} onNext={()=>setStep(3)} />
                </div>
              )}

              {/* ─── STEP 3 ─── */}
              {step===3 && (
                <div>
                  <STitle icon="⚠️" title="ปัจจัยความเสี่ยงทรัพย์" sub="ทำเครื่องหมายปัจจัยที่พบในทรัพย์นี้" />
                  <Card title="">
                    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                      {RISK_FACTORS.map(r => (
                        <div key={r.key} onClick={()=>toggleRisk(r.key)} style={{
                          display:"flex",alignItems:"center",gap:12,padding:"14px 16px",
                          borderRadius:10,cursor:"pointer",transition:"all .2s",
                          background:form.risks[r.key]?"rgba(248,113,113,.1)":"var(--bg3)",
                          border:`1px solid ${form.risks[r.key]?"#f87171":"var(--border)"}`,
                        }}>
                          <div style={{
                            width:22,height:22,borderRadius:6,display:"flex",alignItems:"center",
                            justifyContent:"center",fontSize:13,flexShrink:0,
                            background:form.risks[r.key]?"#f87171":"var(--bg2)",
                            border:`2px solid ${form.risks[r.key]?"#f87171":"var(--border)"}`,
                          }}>{form.risks[r.key]&&"✓"}</div>
                          <div style={{flex:1}}>
                            <div style={{fontSize:14,color:form.risks[r.key]?"#fca5a5":"var(--text1)"}}>{r.label}</div>
                          </div>
                          <div style={{
                            fontFamily:"'IBM Plex Mono',monospace",fontSize:11,padding:"2px 8px",borderRadius:4,
                            color:form.risks[r.key]?"#f87171":"var(--text2)",
                            background:form.risks[r.key]?"rgba(248,113,113,.15)":"var(--bg2)",
                          }}>-{r.weight}pt</div>
                        </div>
                      ))}
                    </div>
                    <div style={{
                      marginTop:20,padding:"16px 20px",borderRadius:10,
                      background:"var(--bg2)",border:"1px solid var(--border)",
                      display:"flex",alignItems:"center",justifyContent:"space-between"
                    }}>
                      <div>
                        <div style={{fontSize:13,color:"var(--text2)"}}>Property Score</div>
                        <div style={{fontSize:36,fontWeight:700,fontFamily:"'IBM Plex Mono',monospace",color:scoreColor(propertyScore)}}>{propertyScore}<span style={{fontSize:16,fontWeight:400}}>/100</span></div>
                        <div style={{fontSize:14,color:scoreColor(propertyScore)}}>{scoreLabel(propertyScore)}</div>
                      </div>
                      <svg viewBox="0 0 36 36" style={{transform:"rotate(-90deg)",width:100,height:100}}>
                        <circle cx="18" cy="18" r="15.9" fill="none" stroke="var(--bg3)" strokeWidth="3" />
                        <circle cx="18" cy="18" r="15.9" fill="none" stroke={scoreColor(propertyScore)} strokeWidth="3" strokeDasharray={`${propertyScore} 100`} strokeLinecap="round" />
                      </svg>
                    </div>
                  </Card>
                  <div style={{marginTop:16}}>
                    <Card title="กำหนด LTV Rate">
                      <div style={{display:"flex",alignItems:"center",gap:16}}>
                        <input type="range" min={20} max={75} value={form.ltvRate}
                          onChange={e=>setF("ltvRate",e.target.value)}
                          style={{flex:1,accentColor:"var(--gold)"}} />
                        <div style={{
                          fontFamily:"'IBM Plex Mono',monospace",fontSize:24,fontWeight:700,minWidth:60,
                          color:form.ltvRate<=45?"var(--green)":form.ltvRate<=60?"var(--gold2)":"var(--red)"
                        }}>{form.ltvRate}%</div>
                      </div>
                      <div style={{display:"flex",justifyContent:"space-between",fontSize:12,color:"var(--text2)",marginTop:4}}>
                        <span>20% — อนุรักษ์นิยม</span><span>50% — มาตรฐาน</span><span>75% — สูงสุด</span>
                      </div>
                    </Card>
                  </div>
                  <NavBtn onBack={()=>setStep(2)} onNext={()=>setStep(4)} nextLabel="ดูผลประเมิน →" />
                </div>
              )}

              {/* ─── STEP 4 — REPORT ─── */}
              {step===4 && (
                <div className="print-page">
                  {/* Report header */}
                  <div style={{padding:"16px 0 20px",borderBottom:"1px solid var(--border)",marginBottom:20}}>
                    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                      <img src={LOGO_B64} alt="AssetX" style={{height:52,objectFit:"contain"}} />
                      <div style={{textAlign:"right"}}>
                        <div style={{fontSize:11,color:"var(--text2)",fontFamily:"'IBM Plex Mono',monospace",letterSpacing:2,textTransform:"uppercase"}}>รายงานประเมินมูลค่าอสังหาริมทรัพย์</div>
                        <div style={{fontSize:11,color:"var(--text2)",marginTop:2,fontFamily:"'IBM Plex Mono',monospace"}}>
                          วันที่ {new Date(form.date).toLocaleDateString("th-TH")} | ผู้ประเมิน: {form.analyst||"—"}
                        </div>
                      </div>
                    </div>
                    <div style={{marginTop:12,paddingTop:12,borderTop:"1px solid var(--border)"}}>
                      <div style={{display:"flex",gap:10,alignItems:"center",marginBottom:6}}>
                        <AssessTypeBadge type={form.assessmentType} />
                        <PropTypeBadge type={form.propertyType} />
                      </div>
                      <div style={{fontSize:22,fontWeight:700,color:"var(--gold2)"}}>{form.projectName||"ที่ดินเปล่า"}</div>
                      <div style={{fontSize:13,color:"var(--text2)",marginTop:4}}>
                        โฉนดเลขที่ {form.titleDeed||"—"} | ต.{form.subdistrict} อ.{form.district} จ.{form.province}
                      </div>
                    </div>
                  </div>

                  {/* Key numbers */}
                  <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:18}}>
                    <BigStat icon="🏛" label="ราคาประเมินรัฐ" value={`฿${fmt(govTotal)}`} sub={`${fmt(parseFloat(form.govPrice||0))} บาท/ตรว.`} color="#8fa3bf" />
                    <BigStat icon="📈" label="ราคาตลาดโดยประมาณ" value={`฿${fmt(finalMarketPrice)}`} sub={`${fmt(finalPricePerSqwa)} บาท/ตรว.`} color="var(--gold2)" />
                    <BigStat icon="🔥" label="Forced Sale Value" value={`฿${fmt(fsv)}`} sub={`${Math.round(fsvDiscount*100)}% ของราคาตลาด`} color="var(--orange)" />
                    <BigStat icon="🏦" label={form.assessmentType==="จำนอง"?"วงเงินจำนองแนะนำ":"วงเงินขายฝากแนะนำ"} value={`฿${fmt(safetyLoan)}`} sub={`LTV ${form.ltvRate}% × FSV`} color="var(--green)" />
                  </div>

                  <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}>
                    <Card title="📋 รายละเอียดทรัพย์">
                      {[
                        ["ประเภทการประเมิน", form.assessmentType],
                        ["ประเภทอสังหาริมทรัพย์", form.propertyType],
                        ["เนื้อที่", `${form.rai} ไร่ ${form.ngaan} งาน ${form.sqwa} ตรว. (${fmt(totalSqwa)} ตรว.)`],
                        ["ราคาประเมินกรมธนารักษ์", `${fmt(parseFloat(form.govPrice||0))} บาท/ตรว.`],
                        ["ทำเล", form.zone],
                        ["ถนนหน้าที่ดิน", form.roadWidth],
                        ["หน้ากว้าง", form.frontage],
                        ["ผังเมือง", form.zoning],
                        ["สภาพการถม", form.fillStatus],
                        ...(form.compPrice ? [["Comparable", `${fmt(form.compPrice)} บาท/ตรว. (${form.compNote})`]] : []),
                      ].map(([k,v],i) => (
                        <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid var(--border)",fontSize:13}}>
                          <span style={{color:"var(--text2)"}}>{k}</span>
                          <span style={{color:"var(--text1)",fontWeight:500,textAlign:"right",maxWidth:"58%"}}>{v}</span>
                        </div>
                      ))}
                    </Card>
                    <div>
                      <Card title="⚠️ ความเสี่ยงและ Score">
                        <div style={{display:"flex",alignItems:"center",gap:16,marginBottom:12}}>
                          <div style={{textAlign:"center"}}>
                            <div style={{fontSize:48,fontWeight:800,fontFamily:"'IBM Plex Mono',monospace",color:scoreColor(propertyScore),lineHeight:1}}>{propertyScore}</div>
                            <div style={{fontSize:11,color:"var(--text2)"}}>/ 100</div>
                            <div style={{fontSize:13,color:scoreColor(propertyScore),marginTop:4}}>{scoreLabel(propertyScore)}</div>
                          </div>
                          <div style={{flex:1}}>
                            {activeRisks.length===0
                              ? <div style={{color:"var(--green)",fontSize:13}}>✅ ไม่พบปัจจัยเสี่ยง</div>
                              : activeRisks.map(r => (
                                <div key={r.key} style={{display:"flex",justifyContent:"space-between",padding:"5px 0",borderBottom:"1px solid var(--border)",fontSize:13}}>
                                  <span style={{color:"#fca5a5"}}>⚠ {r.label}</span>
                                  <span style={{color:"#f87171",fontFamily:"'IBM Plex Mono',monospace"}}>-{r.weight}pt</span>
                                </div>
                              ))}
                          </div>
                        </div>
                      </Card>
                      <div style={{marginTop:12}}>
                        <Card title="💰 สรุปวงเงิน">
                          {[
                            ["มูลค่าตลาด",`฿${fmt(finalMarketPrice)}`,"var(--gold2)"],
                            [`FSV (${Math.round(fsvDiscount*100)}%)`,`฿${fmt(fsv)}`,"var(--orange)"],
                            [`${form.assessmentType==="จำนอง"?"วงเงินจำนอง":"วงเงินขายฝาก"} (LTV ${form.ltvRate}%)`,`฿${fmt(safetyLoan)}`,"var(--green)"],
                          ].map(([k,v,c],i) => (
                            <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"10px 0",borderBottom:"1px solid var(--border)"}}>
                              <span style={{color:"var(--text2)",fontSize:13}}>{k}</span>
                              <span style={{fontFamily:"'IBM Plex Mono',monospace",fontWeight:700,fontSize:i===2?18:14,color:c}}>{v}</span>
                            </div>
                          ))}
                          <div style={{marginTop:12,padding:"12px 16px",borderRadius:8,background:"rgba(74,222,128,.08)",border:"1px solid rgba(74,222,128,.25)",textAlign:"center"}}>
                            <div style={{fontSize:12,color:"var(--text2)"}}>{form.assessmentType==="จำนอง"?"วงเงินจำนองที่แนะนำ":"วงเงินขายฝากที่แนะนำ"}</div>
                            <div style={{fontSize:28,fontWeight:800,color:"var(--green)",fontFamily:"'IBM Plex Mono',monospace"}}>฿{fmt(safetyLoan)}</div>
                          </div>
                        </Card>
                      </div>
                    </div>
                  </div>

                  {form.noteLocation && (
                    <div style={{marginTop:14}}>
                      <Card title="📝 หมายเหตุ"><p style={{fontSize:14,color:"var(--text2)",lineHeight:1.8}}>{form.noteLocation}</p></Card>
                    </div>
                  )}

                  {/* Save status */}
                  {saveStatus && (
                    <div style={{
                      marginTop:16,padding:"14px 20px",borderRadius:10,textAlign:"center",fontSize:14,
                      background:saveStatus==="ok"?"rgba(74,222,128,.1)":saveStatus==="error"?"rgba(248,113,113,.1)":"rgba(201,168,76,.1)",
                      border:`1px solid ${saveStatus==="ok"?"var(--green)":saveStatus==="error"?"var(--red)":"var(--gold)"}`,
                      color:saveStatus==="ok"?"var(--green)":saveStatus==="error"?"var(--red)":"var(--gold2)"
                    }}>
                      {saveStatus==="saving" && "⏳ กำลังบันทึก..."}
                      {saveStatus==="ok" && "✅ บันทึกสำเร็จ! ข้อมูลถูกเก็บในระบบ" + (gsheetUrl?" และส่งไป Google Sheet แล้ว":"")}
                      {saveStatus==="error" && "⚠️ บันทึกในเครื่องแล้ว แต่ Google Sheet เชื่อมต่อไม่ได้ — ตรวจสอบ URL ในการตั้งค่า"}
                    </div>
                  )}

                  <div style={{marginTop:14,padding:"12px 18px",borderRadius:10,background:"var(--bg3)",border:"1px solid var(--border)",display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:12,color:"var(--text2)"}}>
                    <span>AssetX Estate Co., Ltd. — PropVal Pro v2.0</span>
                    <span>Generated: {new Date().toLocaleString("th-TH")}</span>
                  </div>

                  <div className="no-print" style={{marginTop:20,display:"flex",gap:12}}>
                    <button onClick={()=>setStep(3)} style={backBtnStyle}>← แก้ไข</button>
                    <button onClick={handleSave} disabled={saveStatus==="saving"} style={{
                      flex:1,padding:"12px 24px",borderRadius:10,cursor:"pointer",
                      background:"rgba(74,222,128,.12)",color:"var(--green)",
                      border:"1px solid var(--green)",fontFamily:"'Sarabun',sans-serif",
                      fontSize:15,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center",gap:8
                    }}>
                      💾 บันทึก{gsheetUrl?" + ส่ง Google Sheet":"ข้อมูล"}
                    </button>
                    <button onClick={()=>window.print()} style={{
                      padding:"12px 20px",borderRadius:10,cursor:"pointer",
                      background:"linear-gradient(135deg,var(--gold),var(--gold2))",
                      color:"#080c14",border:"none",fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:700
                    }}>📄 PDF</button>
                    <button onClick={()=>{setForm(initForm());setStep(1);}} style={{...backBtnStyle,borderColor:"var(--gold)",color:"var(--gold2)"}}>+ ทรัพย์ใหม่</button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}

        {/* ═══════════════════════════════════ HISTORY VIEW ═══════════════════════ */}
        {view==="history" && (
          <div style={{maxWidth:1100,margin:"0 auto",padding:"28px 20px"}}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:20}}>
              <div>
                <div style={{fontSize:22,fontWeight:700,color:"var(--text1)"}}>📁 ประวัติการประเมิน</div>
                <div style={{fontSize:13,color:"var(--text2)",marginTop:4}}>ทรัพย์ที่ประเมินแล้วทั้งหมด {records.length} รายการ</div>
              </div>
              {records.length>0 && (
                <button onClick={()=>{
                  const csv = ["วันที่,ประเภทการประเมิน,ประเภทอสังหาฯ,ชื่อทรัพย์,โฉนด,ตำบล,อำเภอ,จังหวัด,เนื้อที่(ตรว),ราคารัฐ/ตรว,มูลค่ารัฐ,ราคาตลาด/ตรว,มูลค่าตลาด,FSV,LTV%,วงเงิน,Score,ความเสี่ยง,ผู้ประเมิน",
                    ...records.map(r => [r.date,r.assessmentType,r.propertyType,r.projectName,r.titleDeed,r.subdistrict,r.district,r.province,r.areaSqwa,r.govPricePerSqwa,r.govTotal,r.marketPricePerSqwa,r.marketTotal,r.fsv,r.ltvRate,r.loanAmount,r.propertyScore,`"${r.risks}"`,r.analyst].join(","))
                  ].join("\n");
                  const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([csv],{type:"text/csv;charset=utf-8;"}));
                  a.download=`propval_export_${new Date().toISOString().split("T")[0]}.csv`;a.click();
                }} style={{
                  padding:"10px 20px",borderRadius:8,cursor:"pointer",fontSize:14,fontWeight:600,
                  background:"rgba(201,168,76,.12)",color:"var(--gold2)",border:"1px solid var(--gold)",
                  fontFamily:"'Sarabun',sans-serif"
                }}>⬇ Export CSV</button>
              )}
            </div>

            {records.length===0 ? (
              <div style={{textAlign:"center",padding:"60px 20px",color:"var(--text2)"}}>
                <div style={{fontSize:48,marginBottom:16}}>📋</div>
                <div style={{fontSize:18,fontWeight:600,marginBottom:8}}>ยังไม่มีประวัติการประเมิน</div>
                <div style={{fontSize:14}}>กลับไปประเมินทรัพย์ แล้วกด "บันทึกข้อมูล" ในขั้นตอนที่ 4</div>
              </div>
            ) : (
              <>
                {/* Summary stats */}
                <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:12,marginBottom:20}}>
                  <StatBox label="รายการทั้งหมด" value={records.length} sub="ทรัพย์" color="var(--gold2)" />
                  <StatBox label="วงเงินรวม" value={`฿${fmt(records.reduce((s,r)=>s+r.loanAmount,0))}`} sub="บาท" color="var(--green)" />
                  <StatBox label="ขายฝาก" value={records.filter(r=>r.assessmentType==="ขายฝาก").length} sub="รายการ" color="#f59e0b" />
                  <StatBox label="จำนอง" value={records.filter(r=>r.assessmentType==="จำนอง").length} sub="รายการ" color="#3b82f6" />
                </div>

                {/* Table */}
                <div style={{background:"var(--bg2)",border:"1px solid var(--border)",borderRadius:12,overflow:"hidden"}}>
                  <div style={{overflowX:"auto"}}>
                    <table style={{width:"100%",borderCollapse:"collapse",fontSize:13}}>
                      <thead>
                        <tr style={{background:"var(--bg3)",borderBottom:"1px solid var(--border)"}}>
                          {["วันที่","ประเภท","ทรัพย์","โฉนด","ที่ตั้ง","เนื้อที่","ราคาตลาด","วงเงิน","Score","ดำเนินการ"].map(h => (
                            <th key={h} style={{padding:"12px 14px",textAlign:"left",color:"var(--gold)",fontWeight:600,fontSize:12,letterSpacing:.5,whiteSpace:"nowrap"}}>{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {records.map((r,i) => (
                          <tr key={r.id} style={{borderBottom:"1px solid var(--border)",background:i%2===0?"var(--bg2)":"rgba(255,255,255,.01)"}}>
                            <td style={{padding:"12px 14px",whiteSpace:"nowrap",color:"var(--text2)"}}>{new Date(r.date).toLocaleDateString("th-TH",{day:"numeric",month:"short",year:"2-digit"})}</td>
                            <td style={{padding:"12px 14px",whiteSpace:"nowrap"}}>
                              <AssessTypeBadge type={r.assessmentType} small />
                            </td>
                            <td style={{padding:"12px 14px",maxWidth:160}}>
                              <div style={{fontWeight:600,color:"var(--text1)",fontSize:13}}>{r.projectName||"—"}</div>
                              <div style={{fontSize:11,color:"var(--text2)",marginTop:2}}>{r.propertyType}</div>
                            </td>
                            <td style={{padding:"12px 14px",fontFamily:"'IBM Plex Mono',monospace",color:"var(--text2)"}}>{r.titleDeed||"—"}</td>
                            <td style={{padding:"12px 14px",color:"var(--text2)",fontSize:12}}>ต.{r.subdistrict} อ.{r.district}</td>
                            <td style={{padding:"12px 14px",fontFamily:"'IBM Plex Mono',monospace",whiteSpace:"nowrap",color:"var(--text1)"}}>{fmt(r.areaSqwa)} ตรว.</td>
                            <td style={{padding:"12px 14px",fontFamily:"'IBM Plex Mono',monospace",whiteSpace:"nowrap",color:"var(--gold2)",fontWeight:600}}>฿{fmt(r.marketTotal)}</td>
                            <td style={{padding:"12px 14px",fontFamily:"'IBM Plex Mono',monospace",whiteSpace:"nowrap",color:"var(--green)",fontWeight:700}}>฿{fmt(r.loanAmount)}</td>
                            <td style={{padding:"12px 14px"}}>
                              <span style={{padding:"3px 10px",borderRadius:20,fontSize:12,fontFamily:"'IBM Plex Mono',monospace",background:`${scoreColor(r.propertyScore)}20`,color:scoreColor(r.propertyScore),border:`1px solid ${scoreColor(r.propertyScore)}40`}}>{r.propertyScore}</span>
                            </td>
                            <td style={{padding:"12px 14px",whiteSpace:"nowrap"}}>
                              <button onClick={()=>handleDeleteRecord(r.id)} style={{
                                padding:"4px 10px",borderRadius:6,cursor:"pointer",fontSize:12,
                                background:"rgba(248,113,113,.1)",color:"#f87171",border:"1px solid rgba(248,113,113,.3)",
                                fontFamily:"'Sarabun',sans-serif"
                              }}>ลบ</button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                </div>
              </>
            )}
          </div>
        )}

        {/* ════════════════════════════════════ SETTINGS VIEW ═════════════════════ */}
        {view==="settings" && (
          <div style={{maxWidth:720,margin:"0 auto",padding:"28px 20px"}}>
            <STitle icon="⚙️" title="ตั้งค่าการเชื่อมต่อ Google Sheet" sub="บันทึกข้อมูลการประเมินลง Google Sheets อัตโนมัติ" />

            <Card title="🔗 Google Apps Script Webhook URL">
              <div style={{marginBottom:16,padding:"14px 16px",borderRadius:8,background:"rgba(201,168,76,.06)",border:"1px solid rgba(201,168,76,.2)",fontSize:13,color:"var(--text2)",lineHeight:1.8}}>
                <strong style={{color:"var(--gold2)"}}>วิธีตั้งค่า Google Sheet (ทำครั้งเดียว):</strong><br/>
                1. เปิด Google Sheet ที่ต้องการ → Extensions → Apps Script<br/>
                2. วางโค้ดด้านล่างและกด Deploy → New Deployment → Web App<br/>
                3. ตั้ง "Who has access" เป็น <strong>Anyone</strong> → Copy URL มาวางด้านล่าง
              </div>
              <div style={{marginBottom:12,padding:"14px",borderRadius:8,background:"var(--bg3)",border:"1px solid var(--border)",fontFamily:"'IBM Plex Mono',monospace",fontSize:11,color:"#a5f3fc",lineHeight:1.7,overflowX:"auto"}}>
                {`function doPost(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  const sh = ss.getActiveSheet();
  const d = JSON.parse(e.postData.contents);
  if (sh.getLastRow() === 0) {
    sh.appendRow(["วันที่","ประเภทประเมิน","ประเภทอสังหาฯ","ชื่อทรัพย์",
      "โฉนด","ตำบล","อำเภอ","จังหวัด","เนื้อที่(ตรว)",
      "ราคารัฐ/ตรว","มูลค่ารัฐ","ราคาตลาด/ตรว","มูลค่าตลาด",
      "FSV","LTV%","วงเงิน","Score","ความเสี่ยง","ทำเล","ผังเมือง","สภาพถม","ผู้ประเมิน","หมายเหตุ"]);
  }
  sh.appendRow(d.row);
  return ContentService.createTextOutput(
    JSON.stringify({status:"ok"})
  ).setMimeType(ContentService.MimeType.JSON);
}

function doGet(e) {
  return ContentService.createTextOutput("PropVal Pro - Ready");
}`}
              </div>
              <Row label="Google Apps Script Web App URL">
                <div style={{display:"flex",gap:8}}>
                  <input value={settingInput} onChange={e=>setSettingInput(e.target.value)}
                    placeholder="https://script.google.com/macros/s/..."
                    style={{
                      flex:1,padding:"10px 14px",background:"var(--bg3)",border:"1px solid var(--border)",
                      borderRadius:8,color:"var(--text1)",fontSize:13,fontFamily:"'Sarabun',sans-serif",outline:"none"
                    }} />
                  <button onClick={saveSettings} style={{
                    padding:"10px 20px",borderRadius:8,cursor:"pointer",fontWeight:700,fontSize:14,
                    background:"linear-gradient(135deg,var(--gold),var(--gold2))",color:"#080c14",
                    border:"none",fontFamily:"'Sarabun',sans-serif",whiteSpace:"nowrap"
                  }}>บันทึก URL</button>
                </div>
              </Row>
              {gsheetUrl && (
                <div style={{marginTop:10,padding:"10px 14px",borderRadius:8,background:"rgba(74,222,128,.08)",border:"1px solid rgba(74,222,128,.25)",fontSize:13,color:"var(--green)"}}>
                  ✅ เชื่อมต่อแล้ว — ข้อมูลจะถูกส่งไป Google Sheet อัตโนมัติทุกครั้งที่กด "บันทึก"
                </div>
              )}
              {!gsheetUrl && (
                <div style={{marginTop:10,padding:"10px 14px",borderRadius:8,background:"rgba(201,168,76,.06)",border:"1px solid rgba(201,168,76,.2)",fontSize:13,color:"var(--text2)"}}>
                  ⚠️ ยังไม่ได้ตั้งค่า URL — ข้อมูลจะถูกบันทึกในเครื่องเท่านั้น (สามารถ Export CSV ได้ในหน้าประวัติ)
                </div>
              )}
            </Card>

            <div style={{marginTop:20}}>
              <Card title="📊 คอลัมน์ที่จะบันทึกลง Google Sheet">
                <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8}}>
                  {["วันที่","ประเภทการประเมิน","ประเภทอสังหาฯ","ชื่อทรัพย์","เลขโฉนด","ตำบล","อำเภอ","จังหวัด","เนื้อที่ (ตรว.)", "ราคาประเมินรัฐ/ตรว.","มูลค่าตามราคารัฐ","ราคาตลาด/ตรว.","มูลค่าตลาด","FSV","LTV%","วงเงินแนะนำ","Property Score","ความเสี่ยงที่พบ","ทำเล","ผังเมือง","สภาพการถม","ผู้ประเมิน","หมายเหตุ"].map((c,i) => (
                    <div key={i} style={{padding:"6px 12px",borderRadius:6,background:"var(--bg3)",border:"1px solid var(--border)",fontSize:12,color:"var(--text2)"}}>
                      <span style={{color:"var(--gold)",fontFamily:"'IBM Plex Mono',monospace",marginRight:8}}>{String(i+1).padStart(2,"0")}</span>{c}
                    </div>
                  ))}
                </div>
              </Card>
            </div>
          </div>
        )}
      </div>
    </>
  );
}

// ─── SHARED UI ──────────────────────────────────────────────────────────────
const backBtnStyle = {
  padding:"12px 22px",borderRadius:10,cursor:"pointer",
  background:"transparent",color:"var(--text2)",
  border:"1px solid var(--border)",fontFamily:"'Sarabun',sans-serif",fontSize:14
};

function STitle({icon,title,sub}) {
  return (
    <div style={{marginBottom:20}}>
      <div style={{fontSize:22,fontWeight:700,color:"var(--text1)",display:"flex",alignItems:"center",gap:10}}><span>{icon}</span>{title}</div>
      <div style={{fontSize:13,color:"var(--text2)",marginTop:4}}>{sub}</div>
    </div>
  );
}
function Card({title,children}) {
  return (
    <div style={{background:"var(--bg2)",border:"1px solid var(--border)",borderRadius:12,padding:"18px"}}>
      {title && <div style={{fontSize:12,fontWeight:600,color:"var(--gold)",marginBottom:14,textTransform:"uppercase",letterSpacing:1}}>{title}</div>}
      {children}
    </div>
  );
}
function Row({label,children}) {
  return <div style={{marginBottom:12}}><div style={{fontSize:12,color:"var(--text2)",marginBottom:5}}>{label}</div>{children}</div>;
}
function Input({value,onChange,placeholder,type="text"}) {
  return <input type={type} value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder}
    style={{width:"100%",padding:"9px 12px",background:"var(--bg3)",border:"1px solid var(--border)",borderRadius:8,color:"var(--text1)",fontSize:14,outline:"none"}} />;
}
function NumIn({value,onChange,lbl}) {
  return (
    <div style={{flex:1,textAlign:"center"}}>
      <input type="number" min={0} value={value} onChange={e=>onChange(e.target.value)}
        style={{width:"100%",padding:"9px 6px",textAlign:"center",background:"var(--bg3)",border:"1px solid var(--border)",borderRadius:8,color:"var(--text1)",fontSize:14,fontFamily:"'IBM Plex Mono',monospace",outline:"none"}} />
      <div style={{fontSize:11,color:"var(--text2)",marginTop:3}}>{lbl}</div>
    </div>
  );
}
function Sel({value,onChange,opts}) {
  return <select value={value} onChange={e=>onChange(e.target.value)}
    style={{width:"100%",padding:"9px 12px",background:"var(--bg3)",border:"1px solid var(--border)",borderRadius:8,color:"var(--text1)",fontSize:13,outline:"none"}}>
    {opts.map(o=><option key={o} value={o}>{o}</option>)}
  </select>;
}
function StatBox({label,value,sub,color}) {
  return (
    <div style={{padding:"14px",borderRadius:10,background:"var(--bg3)",border:"1px solid var(--border)",textAlign:"center"}}>
      <div style={{fontSize:11,color:"var(--text2)",marginBottom:5}}>{label}</div>
      <div style={{fontSize:16,fontWeight:700,color,fontFamily:"'IBM Plex Mono',monospace"}}>{value}</div>
      <div style={{fontSize:11,color:"var(--text2)",marginTop:4}}>{sub}</div>
    </div>
  );
}
function BigStat({icon,label,value,sub,color}) {
  return (
    <div style={{padding:"16px",borderRadius:12,background:"var(--bg2)",border:`1px solid ${color}30`,borderTop:`3px solid ${color}`}}>
      <div style={{fontSize:20,marginBottom:5}}>{icon}</div>
      <div style={{fontSize:11,color:"var(--text2)",marginBottom:4,textTransform:"uppercase",letterSpacing:1}}>{label}</div>
      <div style={{fontSize:17,fontWeight:800,color,fontFamily:"'IBM Plex Mono',monospace",lineHeight:1.2}}>{value}</div>
      <div style={{fontSize:11,color:"var(--text2)",marginTop:5}}>{sub}</div>
    </div>
  );
}
function InfoBox({value,label}) {
  return (
    <div style={{marginTop:10,padding:"10px 14px",borderRadius:8,background:"rgba(201,168,76,.08)",border:"1px solid rgba(201,168,76,.2)"}}>
      <div style={{fontSize:19,fontWeight:700,color:"var(--gold2)",fontFamily:"'IBM Plex Mono',monospace"}}>{value}</div>
      <div style={{fontSize:11,color:"var(--text2)",marginTop:2}}>{label}</div>
    </div>
  );
}
function NavBtn({onBack,onNext,nextLabel="ถัดไป →"}) {
  return (
    <div style={{display:"flex",gap:12,marginTop:22}}>
      {onBack && <button onClick={onBack} style={backBtnStyle}>← ย้อนกลับ</button>}
      {onNext && <button onClick={onNext} style={{flex:1,padding:"12px 24px",borderRadius:10,cursor:"pointer",background:"linear-gradient(135deg,#b8972a,var(--gold2))",color:"#080c14",border:"none",fontFamily:"'Sarabun',sans-serif",fontSize:15,fontWeight:700}}>{nextLabel}</button>}
    </div>
  );
}
function AssessTypeBadge({type,small}) {
  const t = ASSESSMENT_TYPES.find(x=>x.value===type)||ASSESSMENT_TYPES[5];
  return (
    <span style={{
      display:"inline-flex",alignItems:"center",gap:4,
      padding:small?"3px 10px":"5px 14px",borderRadius:20,fontSize:small?11:13,fontWeight:600,
      background:`${t.color}20`,color:t.color,border:`1px solid ${t.color}50`
    }}>{t.icon} {type}</span>
  );
}
function PropTypeBadge({type}) {
  return (
    <span style={{
      display:"inline-flex",alignItems:"center",gap:4,
      padding:"4px 12px",borderRadius:20,fontSize:12,fontWeight:500,
      background:"rgba(96,165,250,.1)",color:"#60a5fa",border:"1px solid rgba(96,165,250,.3)"
    }}>🏠 {type}</span>
  );
}
